-- Tier B: one-directional letters/notices get a single signature field
-- appended for the sender (or the HR/manager issuing the letter).
-- Idempotent: only appends if a field with that name doesn't already
-- exist.

UPDATE document_templates SET fields_schema = JSON_ARRAY_APPEND(fields_schema, '$.fields', JSON_OBJECT('name', 'sender_signature', 'label', 'Sender Signature', 'type', 'signature', 'required', false)) WHERE slug = 'cease-and-desist-letter-generator' AND JSON_SEARCH(fields_schema, 'one', 'sender_signature', NULL, '$.fields[*].name') IS NULL;
